const r = $input.first().json;
const calls = (r && r.calls) || [];
const pad = n => String(n).padStart(2, '0');
return calls.filter(c => c.recordingSid || c.callSid).map(c => {
  const key = c.recordingSid || c.callSid;
  const raw = c.callStart || c.date || '';
  const d = new Date(raw);
  const date = isNaN(d.getTime()) ? raw : `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
  return { json: {
    'Recording SID': key,
    Date: date,
    Caller: c.phone || '',
    Source: c.source || '',
    'Duration (s)': c.duration || 0,
    Booked: c.booked || '',
    Job: c.jobType || (c.spam ? 'SPAM' : ''),
    Size: c.dumpsterSize || '',
    'Quoted $': c.quotedPrice || '',
    City: c.city || '',
    Summary: c.summary || '',
    Transcript: (c.transcript || '').slice(0, 4000),
    Recording: c.recordingSid ? ('https://agencycommandcenter.ai/api/calls/recording/' + c.recordingSid) : ''
  } };
});
